import { useState, useEffect } from "react";
import { Toaster as Sonner, toast } from "sonner";

export const Toaster = (props) => {
  const [theme, setTheme] = useState(() =>
    typeof document !== "undefined" && document.documentElement.classList.contains("dark") ? "dark" : "light"
  );

  useEffect(() => {
    const observer = new MutationObserver(() => {
      const isDark = document.documentElement.classList.contains("dark");
      setTheme(isDark ? "dark" : "light");
    });
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ["class"] });
    return () => observer.disconnect();
  }, []);

  return (
    <Sonner
      theme={theme}
      className="toaster group"
      position="bottom-right"
      toastOptions={{
        classNames: {
          toast: `group toast border font-mono text-sm ${
            theme === "dark"
              ? "bg-bg-base text-white border-white/15 shadow-[0_8px_32px_rgba(0,0,0,0.5)]"
              : "bg-white text-zinc-900 border-zinc-200 shadow-[0_8px_32px_rgba(0,0,0,0.1)]"
          }`,
          description: theme === "dark" ? "text-zinc-400" : "text-zinc-500",
          actionButton: "bg-emerald-500 text-black",
          cancelButton: theme === "dark" ? "bg-white/10 text-white" : "bg-zinc-100 text-zinc-700",
        },
      }}
      {...props}
    />
  );
};

export { toast };
