import { Link } from "react-router-dom";
import { ChevronRight } from "lucide-react";

export default function Breadcrumb({ items, icon: Icon, color = "text-emerald-400", className = "" }) {
  return (
    <nav className={`font-mono text-[11px] uppercase tracking-[0.25em] mb-4 inline-flex items-center gap-1.5 flex-wrap ${className}`}>
      {Icon && <Icon className={`w-3 h-3 ${color}`} />}
      {items.map((item, i) => (
        <span key={i} className="inline-flex items-center gap-1.5">
          {i > 0 && <ChevronRight className="w-2.5 h-2.5 text-zinc-500" />}
          {item.href ? (
            <Link to={item.href} className={`${color} hover:opacity-80 transition-opacity`}>
              {item.label}
            </Link>
          ) : (
            <span className="text-zinc-400">{item.label}</span>
          )}
        </span>
      ))}
    </nav>
  );
}
