import { useState, useEffect, useMemo, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { X, ArrowUpRight, Package, MapPin, Store, ChevronDown, ChevronRight, RefreshCw } from "lucide-react";
import { fetchChestShops } from "@/lib/castiaClient";
import { fmt } from "@/lib/parseItem";
import FreshnessPill from "./FreshnessPill";
import ItemName from "./ItemName";
import Breadcrumb from "@/components/ui/Breadcrumb";

const FETCH_LIMIT = 500;
const CACHE_TTL = 60_000;

const cache = new Map();

function median(arr) {
  if (arr.length === 0) return null;
  const sorted = [...arr].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

function ShopDetailPanel({ itemName, onClose, onOpenSeller }) {
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [lastFetched, setLastFetched] = useState(null);

  const doFetch = useCallback(async () => {
    const cached = cache.get(itemName);
    if (cached && Date.now() - cached.ts < CACHE_TTL) {
      setData(cached.data);
      setLoading(false);
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const res = await fetchChestShops({ item: itemName, limit: FETCH_LIMIT });
      const rows = Array.isArray(res) ? res : res?.shops || [];
      const ts = Date.now();
      cache.set(itemName, { data: rows, ts });
      setData(rows);
      setLastFetched(ts);
    } catch (e) {
      setError(e.message || "Failed to load shop data");
    } finally {
      setLoading(false);
    }
  }, [itemName]);

  useEffect(() => { doFetch(); }, [doFetch]);

  const stats = useMemo(() => {
    if (!data || data.length === 0) return null;
    const prices = data.map((r) => r.unitPrice).filter((p) => p > 0);
    const sellers = new Set(data.map((r) => r.seller));
    const min = prices.length > 0 ? Math.min(...prices) : null;
    const max = prices.length > 0 ? Math.max(...prices) : null;
    return {
      totalShops: data.length,
      uniqueSellers: sellers.size,
      prices,
      medianPrice: median(prices),
      minPrice: min,
      maxPrice: max,
    };
  }, [data]);

  const topCheapest = useMemo(() => {
    if (!data || data.length === 0) return [];
    return [...data]
      .filter((r) => r.unitPrice > 0)
      .sort((a, b) => a.unitPrice - b.unitPrice)
      .slice(0, 3);
  }, [data]);

  const sellersGrouped = useMemo(() => {
    if (!data) return [];
    const map = new Map();
    for (const r of data) {
      if (!map.has(r.seller)) map.set(r.seller, []);
      map.get(r.seller).push(r);
    }
    return [...map.entries()]
      .map(([seller, shops]) => {
        const warpMap = new Map();
        for (const s of shops) {
          const key = s.warpName || null;
          if (!warpMap.has(key)) warpMap.set(key, []);
          warpMap.get(key).push(s);
        }
        const warps = [...warpMap.entries()].map(([warp, ws]) => ({
          warpName: warp,
          shops: ws.sort((a, b) => a.unitPrice - b.unitPrice),
        })).sort((a, b) => {
          if (a.warpName === null) return 1;
          if (b.warpName === null) return -1;
          return a.warpName.localeCompare(b.warpName);
        });
        return { seller, shops, warps };
      })
      .sort((a, b) => b.shops.length - a.shops.length);
  }, [data]);

  const closeWithSeller = (name) => {
    if (onOpenSeller) onOpenSeller(name);
  };

  return (
    <div className="flex flex-col h-full">
      <div className="sticky top-0 z-10 bg-bg-base/95 backdrop-blur-xl border-b border-white/10 px-6 sm:px-8 py-4 flex items-center justify-between">
        <Breadcrumb
          items={[
            { label: "Home", href: "/" },
            { label: "Shops", href: "/shops" },
            { label: itemName },
          ]}
          color="text-emerald-400"
          className="mb-0 text-[10px]"
        />
        <button onClick={onClose} data-testid="drawer-close" aria-label="Close" className="p-2 text-zinc-400 hover:text-white transition-colors">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar">
        {loading && (
          <div className="flex items-center justify-center py-24">
            <RefreshCw className="w-5 h-5 text-zinc-500 animate-spin" />
          </div>
        )}

        {error && (
          <div className="p-10 text-center">
            <p className="text-red-400 text-sm mb-4">{error}</p>
            <button
              onClick={doFetch}
              className="inline-flex items-center gap-2 bg-white/[0.06] hover:bg-white/[0.1] border border-white/10 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2.5 rounded-sm transition-colors"
            >
              <RefreshCw className="w-3.5 h-3.5" /> Retry
            </button>
          </div>
        )}

        {!loading && !error && data && data.length === 0 && (
          <div className="p-10 text-center">
            <Store className="w-8 h-8 text-zinc-600 mx-auto mb-3" />
            <p className="text-zinc-400 text-sm">No chest shop listings found for this item.</p>
          </div>
        )}

        {!loading && !error && data && data.length > 0 && (
          <>
            <div className="px-6 sm:px-8 pt-8 pb-2">
              <div className="flex items-start justify-between gap-4">
                <div>
                  <ItemName name={itemName} className="text-2xl sm:text-3xl font-heading font-black tracking-tighter" layout="wrap" />
                  <p className="mt-1 font-mono text-[11px] text-zinc-500">
                    {stats.totalShops} listing{stats.totalShops !== 1 ? "s" : ""} across {stats.uniqueSellers} seller{stats.uniqueSellers !== 1 ? "s" : ""}
                  </p>
                  <div className="mt-1">
                    <FreshnessPill ms={lastFetched} prefix="Stock" size="xs" />
                  </div>
                </div>
                <button
                  data-testid="view-auction-data"
                  onClick={() => { onClose(); navigate(`/item/${encodeURIComponent(itemName.toLowerCase())}`); }}
                  className="shrink-0 inline-flex items-center gap-1.5 border border-white/10 hover:border-white/30 text-zinc-400 hover:text-white font-mono text-[10px] uppercase tracking-wider px-3 py-1.5 rounded-sm transition-colors"
                >
                  Auction data <ArrowUpRight className="w-3 h-3" />
                </button>
              </div>
            </div>

            {/* Price summary card */}
            <div className="mx-6 sm:mx-8 mt-4 bg-white/[0.02] border border-white/10 rounded-2xl p-5">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-3">Chest Shop Prices</div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                <div>
                  <div className="font-mono text-[9px] uppercase tracking-[0.2em] text-zinc-500">Median</div>
                  <div className="font-heading text-xl font-bold text-indigo-400 tabular mt-0.5">
                    {stats.medianPrice != null ? fmt(stats.medianPrice) : "\u2014"}
                  </div>
                </div>
                <div>
                  <div className="font-mono text-[9px] uppercase tracking-[0.2em] text-zinc-500">Min</div>
                  <div className="font-heading text-xl font-bold text-emerald-400 tabular mt-0.5">
                    {stats.minPrice != null ? fmt(stats.minPrice) : "\u2014"}
                  </div>
                </div>
                <div>
                  <div className="font-mono text-[9px] uppercase tracking-[0.2em] text-zinc-500">Max</div>
                  <div className="font-heading text-xl font-bold text-red-400 tabular mt-0.5">
                    {stats.maxPrice != null ? fmt(stats.maxPrice) : "\u2014"}
                  </div>
                </div>
                <div>
                  <div className="font-mono text-[9px] uppercase tracking-[0.2em] text-zinc-500">Range</div>
                  <div className="font-heading text-xl font-bold text-white tabular mt-0.5">
                    {stats.minPrice != null && stats.maxPrice != null
                      ? `\u00d7${(stats.maxPrice / stats.minPrice).toFixed(1)}`
                      : "\u2014"}
                  </div>
                </div>
              </div>
            </div>

            {/* Top 3 cheapest */}
            <div className="px-6 sm:px-8 mt-8">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-3">Top 3 Cheapest</div>
              <div className="space-y-2">
                {topCheapest.map((r, i) => (
                  <motion.div
                    key={`${r.seller}-${r.x}-${r.y}-${r.z}`}
                    initial={{ opacity: 0, y: 6 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.05 }}
                    className="flex items-center gap-3 bg-white/[0.02] border border-white/[0.06] rounded-xl px-4 py-3"
                  >
                    <span className="font-mono text-[10px] text-zinc-600 w-4 shrink-0">#{i + 1}</span>
                    <div className="min-w-0 flex-1">
                      <button
                        onClick={() => closeWithSeller(r.seller)}
                        className="font-medium text-sm text-zinc-200 hover:text-emerald-400 transition-colors truncate max-w-full text-left"
                      >
                        {r.seller}
                      </button>
                      <div className="flex items-center gap-2 mt-0.5 text-[11px] text-zinc-500">
                        <span className="inline-flex items-center gap-1"><Package className="w-3 h-3" />{r.stockCount != null ? `${r.stockCount}\u00d7` : "\u2014"}</span>
                        {r.warpName && <span className="inline-flex items-center gap-1"><MapPin className="w-3 h-3" />{r.warpName}</span>}
                      </div>
                    </div>
                    <span className="font-mono tabular text-indigo-400 font-bold shrink-0">{fmt(r.unitPrice)}</span>
                  </motion.div>
                ))}
                {topCheapest.length === 0 && (
                  <div className="text-zinc-600 text-xs font-mono">No priced listings.</div>
                )}
              </div>
            </div>

            {/* All sellers (collapsible) */}
            <div className="px-6 sm:px-8 mt-8 pb-10">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-3">
                All Sellers ({sellersGrouped.length})
              </div>
              <div className="space-y-3">
                {sellersGrouped.map((sg) => (
                  <SellerSection key={sg.seller} seller={sg.seller} warps={sg.warps} shopCount={sg.shops.length} onOpenSeller={closeWithSeller} />
                ))}
              </div>
            </div>
          </>
        )}

        {!loading && !error && stats && stats.totalShops >= FETCH_LIMIT && (
          <div className="px-6 sm:px-8 pb-10 -mt-6">
            <p className="font-mono text-[10px] uppercase tracking-wider text-zinc-600">
              Showing top {FETCH_LIMIT} listings \u2014 refine with item search for more.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

function SellerSection({ seller, warps, shopCount, onOpenSeller }) {
  const [open, setOpen] = useState(true);
  const [expanded, setExpanded] = useState(false);
  const allShops = warps.flatMap((w) => w.shops);
  const needsShowMore = allShops.length > 5;
  // When not expanded, pass a shopLimit to WarpSection to cap total shops
  const shopLimit = expanded ? null : 5;

  return (
    <div className="bg-white/[0.02] border border-white/[0.06] rounded-xl overflow-hidden">
      <button
        onClick={() => setOpen(!open)}
        className="w-full flex items-center justify-between gap-3 px-4 py-3 hover:bg-white/[0.03] transition-colors text-left"
      >
        <div className="min-w-0 flex-1">
          <button
            onClick={(e) => { e.stopPropagation(); onOpenSeller(seller); }}
            className="font-medium text-sm text-zinc-200 hover:text-emerald-400 transition-colors text-left"
          >
            {seller}
          </button>
          <div className="font-mono text-[10px] text-zinc-500 mt-0.5">{shopCount} listing{shopCount !== 1 ? "s" : ""}</div>
        </div>
        {open ? <ChevronDown className="w-4 h-4 text-zinc-500 shrink-0" /> : <ChevronRight className="w-4 h-4 text-zinc-500 shrink-0" />}
      </button>
      {open && (
        <div className="border-t border-white/[0.04]">
          <WarpSectionLimited warps={warps} shopLimit={shopLimit} />
          {needsShowMore && (
            <div className="px-4 py-2 border-t border-white/[0.04]">
              <button
                onClick={() => setExpanded(!expanded)}
                className="text-[10px] font-mono uppercase tracking-wider text-emerald-400 hover:text-emerald-300 transition-colors"
              >
                {expanded ? "Show less" : `Show ${allShops.length - 5} more`}
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function WarpSectionLimited({ warps, shopLimit }) {
  // Flatten all shops and apply limit if specified
  const allShops = warps.flatMap((w) =>
    w.shops.map((s) => ({ ...s, warpName: w.warpName }))
  );
  const visibleShops = shopLimit ? allShops.slice(0, shopLimit) : allShops;

  // Group visible shops back into warps for display
  const warpsToShow = visibleShops.reduce((acc, shop) => {
    const key = shop.warpName || null;
    if (!acc[key]) acc[key] = [];
    acc[key].push(shop);
    return acc;
  }, {});

  return (
    <div>
      {Object.entries(warpsToShow).map(([warpName, shops]) => (
        <div key={warpName || "__nowarp"}>
          <div className="flex items-center gap-2 min-w-0 px-5 py-2">
            <MapPin className="w-3 h-3 text-zinc-500 shrink-0" />
            <span className="font-mono text-[11px] text-zinc-400">{warpName || "No warp"}</span>
          </div>
          <div className="border-t border-white/[0.04]">
            {shops.map((s) => (
              <div key={`${s.x}-${s.y}-${s.z}`} className="flex items-center gap-3 px-6 py-2 hover:bg-white/[0.02] transition-colors text-sm border-b border-white/[0.02] last:border-0">
                <span className="font-mono text-indigo-400 font-bold tabular w-20 shrink-0 text-right">{fmt(s.unitPrice)}</span>
                <span className="text-zinc-400 min-w-0 flex-1 truncate">
                  {s.stockCount != null ? `${s.stockCount}\u00d7 ${s.stockItemName || "\u2014"}` : "\u2014"}
                </span>
                <span className="font-mono text-[10px] text-zinc-600 shrink-0 hidden sm:inline">
                  ({s.x}, {s.y}, {s.z})
                </span>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

export default ShopDetailPanel;
