// PWA install prompt. Listens for the 'beforeinstallprompt' event and
// surfaces a small banner letting the user add the app to their home
// screen. Dismissal is remembered in localStorage so we don't pester.

import { useEffect, useState } from "react";
import { Download, X, Smartphone } from "lucide-react";

const DISMISS_KEY = "castia.install.dismissed";
const MIN_DISMISS_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

export default function InstallPrompt() {
  const [deferred, setDeferred] = useState(null);
  const [show, setShow] = useState(false);

  useEffect(() => {
    // Has the user dismissed recently? If so, stay quiet.
    const dismissedAt = parseInt(localStorage.getItem(DISMISS_KEY) || "0", 10);
    if (dismissedAt && Date.now() - dismissedAt < MIN_DISMISS_MS) return;

    const handler = (e) => {
      e.preventDefault();
      setDeferred(e);
      // Small delay so the banner doesn't pop on the very first paint.
      const t = setTimeout(() => setShow(true), 1500);
      return () => clearTimeout(t);
    };
    window.addEventListener("beforeinstallprompt", handler);

    // If the app is already installed, the standalone media query
    // is true and we have nothing to offer.
    const mq = window.matchMedia("(display-mode: standalone)");
    if (mq.matches) {
      window.removeEventListener("beforeinstallprompt", handler);
      return;
    }

    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const handleInstall = async () => {
    if (!deferred) return;
    setShow(false);
    try {
      await deferred.prompt();
      await deferred.userChoice;
    } catch {
      /* user dismissed native dialog */
    } finally {
      setDeferred(null);
    }
  };

  const handleDismiss = () => {
    setShow(false);
    localStorage.setItem(DISMISS_KEY, String(Date.now()));
  };

  if (!show || !deferred) return null;

  return (
    <div
      data-testid="install-prompt"
      role="dialog"
      aria-label="Install Castia"
      className="fixed bottom-4 left-4 right-4 z-40 max-w-sm bg-bg-base/95 backdrop-blur-xl border border-emerald-500/30 rounded-2xl p-4 shadow-2xl animate-in fade-in slide-in-from-bottom-2"
    >
      <div className="flex items-start gap-3">
        <div className="shrink-0 w-9 h-9 rounded-lg bg-emerald-500/15 border border-emerald-500/30 grid place-items-center">
          <Smartphone className="w-4 h-4 text-emerald-400" />
        </div>
        <div className="flex-1 min-w-0">
          <div className="font-heading font-bold text-sm text-white">Install Castia</div>
          <p className="text-zinc-400 text-xs mt-1 leading-relaxed">
            Add to your home screen for quick access, full-screen mode, and offline shell.
          </p>
          <div className="mt-3 flex items-center gap-2">
            <button
              data-testid="install-prompt-accept"
              onClick={handleInstall}
              className="inline-flex items-center gap-1.5 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
            >
              <Download className="w-3 h-3" /> Install
            </button>
            <button
              data-testid="install-prompt-dismiss"
              onClick={handleDismiss}
              className="border border-white/10 hover:border-white/20 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
            >
              Not now
            </button>
          </div>
        </div>
        <button
          onClick={handleDismiss}
          aria-label="Dismiss install prompt"
          className="text-zinc-500 hover:text-white transition-colors p-1 -mt-1 -mr-1"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}
